config.script:
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function pageText(){var t=(document.title||'').toLowerCase();var b=(document.body?document.body.innerText:'')||'';return t+' '+b.toLowerCase();}
function networkErr(){var s=pageText();return s.includes("this site can't be reached")||s.includes("this site can’t be reached")||s.includes('err_connection')||s.includes('err_tunnel')||s.includes('err_proxy')||s.includes('err_timed_out')||s.includes('dns_probe_finished')||s.includes('check if there is a typo');}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function emailReady(){var sels=['input[name="Email"]','#input-54','input[type="email"]','form input'];for(var i=0;i<sels.length;i++){var el=document.querySelector(sels[i]);if(vis(el))return true;}return false;}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+25000;
while(Date.now()<deadline){
  if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
  if(emailReady()) return (document.title||'').trim();
  await sleep(500);
}
if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
throw new Error('OASIS signup page did not load an email field in time.');

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
async function tryGet(u,map){try{var r=await fetch(u,{cache:'no-store'});if(!r.ok)return null;var j=await r.json();var g=map(j);return (g&&g.cc)?g:null;}catch(e){return null;}}
var g = await tryGet('https://ipapi.co/json/',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:String(j.country_calling_code||'').replace('+','')};})
     || await tryGet('https://ipwho.is/',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:String(j.calling_code||'').replace('+','')};})
     || await tryGet('https://get.geojs.io/v1/ip/geo.json',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:''};});
if(!g||!g.cc) throw new Error('Could not resolve the proxy geo (IP geolocation failed) - check/rotate the proxy.');
if(!g.city) g.city=g.region||'';
return g;

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+10000;
while(Date.now()<deadline){
  var box=Array.from(document.querySelectorAll('.v-input--selection-controls input[type="checkbox"], input[type="checkbox"]')).filter(vis)[0];
  if(box){
    if(box.checked) return 'agree-checked';
    var wrap=box.closest('.v-input--selection-controls')||box.parentElement;
    var target=(wrap&&wrap.querySelector('.v-input--selection-controls__ripple'))||wrap||box;
    target.scrollIntoView({block:'center'}); target.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
    box.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
  }
  await sleep(300);
}
return 'no-agree-checkbox';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function textInputs(){return Array.from(document.querySelectorAll('input')).filter(function(i){var t=(i.type||'').toLowerCase();return vis(i)&&(t===''||t==='text');});}
function detailsReady(){
  if(vis(document.querySelector('input[type="tel"]'))) return true;
  if(vis(document.querySelector('input[autocomplete="no-thanks"]'))) return true;
  // Location-only variant: no phone, no name fields - just one text box that
  // is not the email field we already filled.
  return textInputs().filter(function(i){return i.name!=='Email';}).length>0;
}
function loginPrompt(){return vis(document.querySelector('input[type="password"]'));}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<20000){await sleep(200);}
var deadline=Date.now()+30000;
while(Date.now()<deadline){
  if(detailsReady()) return 'signup';
  if(loginPrompt()) throw new Error('OASIS account already exists for this email - marking email as used.');
  await sleep(300);
}
if(loginPrompt()) throw new Error('OASIS account already exists for this email - marking email as used.');
throw new Error('Email step did not resolve to the signup details form.');

// ADAPTIVE name step. The details form has two shapes: the full one (first
// name, last name, country, phone, location, DOB) and a reduced one that asks
// for LOCATION ONLY. The old build filled inputs by POSITION
// ((//input[@type='text'])[1] / [2]), so on the reduced form it typed the first
// name straight into the location box and then stalled looking for [2].
//
// Locale-independent anchor: the location field is the one carrying
// autocomplete="no-thanks" (a site attribute, not translated text). Real name
// fields are the visible text inputs that come BEFORE it in document order.
// Zero of those => location-only => fill nothing here and let n_address do it.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function setVal(el,val){el.focus();var s=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;s.call(el,val);el.dispatchEvent(new Event('input',{bubbles:true}));el.dispatchEvent(new Event('change',{bubbles:true}));el.dispatchEvent(new Event('blur',{bubbles:true}));}
function after(ref,el){return !!ref && !!(ref.compareDocumentPosition(el)&Node.DOCUMENT_POSITION_FOLLOWING);}
function locField(){return document.querySelector('input[autocomplete="no-thanks"]');}
function cands(){
  var loc=locField();
  return Array.from(document.querySelectorAll('input')).filter(function(i){
    var t=(i.type||'').toLowerCase();
    if(!vis(i)) return false;
    if(t!==''&&t!=='text') return false;              // skips tel / email / checkbox
    if(i.name==='Email') return false;
    if(i.getAttribute('autocomplete')==='no-thanks') return false;  // the location box
    if(i.closest('.vue-country-select')) return false;              // country search box
    if(i.readOnly) return false;                      // DOB picker box, never a name
    if(loc&&!after(i,loc)) return false;              // anything after location = DOB
    return true;
  });
}
var first=String("{{identity.firstName}}"||'').trim();
var last=String("{{identity.lastName}}"||'').trim();
var deadline=Date.now()+20000;
while(Date.now()<deadline){
  if(vis(locField())||vis(document.querySelector('input[type="tel"]'))) break;
  await sleep(300);
}
await sleep(400);
var loc=locField();
var f=cands();
// Location-only: the page asks for nothing but the location.
if(loc&&f.length===0) return 'location-only';
// No location anchor AND not the familiar two-field layout - refuse to guess
// rather than risk typing a name into whatever box happens to be first.
if(!loc&&f.length<2) return 'ambiguous-skip';
if(loc&&f.length===1){ setVal(f[0],(first+' '+last).trim()); return 'single-name-field'; }
setVal(f[0],first);
await sleep(120);
setVal(f[1],last);
return 'names-filled-'+f.length;

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var iso=String("{{vars.geo.cc}}"||"").trim().toLowerCase();
if(!iso) return 'no-country';
var trigger=document.querySelector('.vue-country-select .dropdown')||document.querySelector('.vue-country-select');
if(!trigger) return 'no-country-widget';
trigger.click(); await sleep(600);
var items=Array.from(document.querySelectorAll('.vue-country-select .dropdown-item, .vue-country-select .dropdown-list li')).filter(vis);
var target=items.find(function(li){return li.querySelector('.vti__flag.'+iso);});
if(!target){ trigger.click(); return 'country-not-found:'+iso; }
target.scrollIntoView({block:'center'}); target.click(); await sleep(300);
return 'country-'+iso;

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function setVal(el,val){el.focus();var s=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;s.call(el,val);el.dispatchEvent(new Event('input',{bubbles:true}));el.dispatchEvent(new Event('change',{bubbles:true}));el.dispatchEvent(new Event('blur',{bubbles:true}));}
function d(n){var s='';for(var i=0;i<n;i++)s+=Math.floor(Math.random()*10);return s;}
function pick(a){return a[Math.floor(Math.random()*a.length)];}
// Reduced (location-only) form has no phone field - skip instead of failing.
var el=document.querySelector('input[type="tel"]');
if(!el) return 'no-phone';
var cc=String("{{vars.geo.cc}}"||"").toUpperCase();
var gens={
  US:function(){return pick('23456789'.split(''))+d(2)+pick('23456789'.split(''))+d(6);},
  GB:function(){return '7'+pick(['4','7','8','9'])+d(8);},
  IE:function(){return '8'+pick(['3','5','6','7','9'])+d(7);},
  ES:function(){return pick(['6','7'])+d(8);},
  FR:function(){return pick(['6','7'])+d(8);},
  DE:function(){return '15'+d(9);},
  IT:function(){return '3'+pick(['1','2','3','4','5','6','8'])+d(8);},
  NL:function(){return '6'+d(8);},
  AU:function(){return '4'+d(8);},
  PT:function(){return '9'+pick(['1','2','3','6'])+d(7);},
  BE:function(){return '4'+pick(['5','6','7','8','9'])+d(7);},
  PL:function(){return pick(['5','6','7','8'])+d(8);},
  SE:function(){return '7'+pick(['0','2','3','6','9'])+d(7);},
  CH:function(){return '7'+pick(['5','6','7','8','9'])+d(7);},
  AT:function(){return '6'+pick(['5','6','7','8','9'])+d(8);},
  BR:function(){return pick(['11','21','31','41','51','61','71','81'])+'9'+d(8);},
  MX:function(){return '1'+d(9);}
};
gens.CA=gens.US;
var num=(gens[cc]?gens[cc]():d(9));
setVal(el,num);
await sleep(150);
return {cc:cc,num:num};

// The DOB field sits right after the location box when there is one. On the
// variant that has names but NO location, fall back to probing the trailing
// text inputs and only accept one that actually opens a date picker.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function textInputs(){return Array.from(document.querySelectorAll('input')).filter(function(i){var t=(i.type||'').toLowerCase();return vis(i)&&(t===''||t==='text');});}
function after(ref,el){return !!ref && !!(ref.compareDocumentPosition(el)&Node.DOCUMENT_POSITION_FOLLOWING);}
function pickerUp(){return !!document.querySelector('.v-date-picker-years, .v-date-picker-table, .v-picker__body');}
var city=document.querySelector('input[autocomplete="no-thanks"]');
var texts=textInputs();
var cands = city ? texts.filter(function(i){return after(city,i);})
                 : texts.slice().reverse().slice(0,3);
for(var k=0;k<cands.length;k++){
  cands[k].scrollIntoView({block:'center'});
  cands[k].click();
  await sleep(500);
  if(pickerUp()) return 'dob-opened';
}
return 'no-dob';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
async function waitFor(fn,ms){var d=Date.now()+ms;while(Date.now()<d){var v=fn();if(v)return v;await sleep(200);}return null;}
// n_dobopen returns 'no-dob' when the form has no date field; the picker then
// never opens, so bail out quietly instead of throwing.
if(String("{{vars.oasisDobOpen}}"||'')==='no-dob') return 'no-dob';
var age=20+Math.floor(Math.random()*36);
var year=(new Date()).getFullYear()-age;
var yearLi=await waitFor(function(){
  var lis=Array.from(document.querySelectorAll('.v-date-picker-years li, .v-picker__body ul li'));
  return lis.find(function(el){return vis(el)&&String(el.textContent||'').trim()===String(year);});
},15000);
if(!yearLi){
  var anyLis=Array.from(document.querySelectorAll('.v-date-picker-years li, .v-picker__body ul li')).filter(vis);
  if(!anyLis.length) return 'no-dob';
  yearLi=anyLis[Math.floor(anyLis.length/2)];
  year=parseInt(String(yearLi.textContent||'').trim(),10)||year;
}
yearLi.scrollIntoView({block:'center'});
yearLi.click();
await sleep(800);
var monthBtns=await waitFor(function(){
  var b=Array.from(document.querySelectorAll('.v-date-picker-table--month button, .v-date-picker-table--month .v-btn')).filter(function(el){return vis(el)&&!el.disabled;});
  return b.length?b:null;
},10000);
if(!monthBtns) throw new Error('DOB month picker not found.');
var mi=Math.floor(Math.random()*monthBtns.length);
monthBtns[mi].scrollIntoView({block:'center'});
monthBtns[mi].click();
await sleep(800);
var dayBtns=await waitFor(function(){
  var b=Array.from(document.querySelectorAll('.v-date-picker-table--date button, .v-date-picker-table--date .v-btn')).filter(function(el){return vis(el)&&!el.disabled&&String(el.textContent||'').trim();});
  return b.length?b:null;
},10000);
if(!dayBtns) throw new Error('DOB day picker not found.');
var di=Math.floor(Math.random()*dayBtns.length);
var dayText=String(dayBtns[di].textContent||'').trim();
dayBtns[di].scrollIntoView({block:'center'});
dayBtns[di].click();
await sleep(500);
return year+'-'+(mi+1)+'-'+dayText;

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+10000;
while(Date.now()<deadline){
  var box=Array.from(document.querySelectorAll('.v-input--selection-controls input[type="checkbox"], input[type="checkbox"]')).filter(vis)[0];
  if(box){
    if(box.checked) return 'agree-checked';
    var wrap=box.closest('.v-input--selection-controls')||box.parentElement;
    var target=(wrap&&wrap.querySelector('.v-input--selection-controls__ripple'))||wrap||box;
    target.scrollIntoView({block:'center'}); target.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
    box.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
  }
  await sleep(300);
}
return 'no-agree-checkbox';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function textInputs(){return Array.from(document.querySelectorAll('input')).filter(function(i){var t=(i.type||'').toLowerCase();return vis(i)&&(t===''||t==='text');});}
function after(ref,el){return !!ref && !!(ref.compareDocumentPosition(el)&Node.DOCUMENT_POSITION_FOLLOWING);}
function detailsUp(){
  if(vis(document.querySelector('input[type="tel"]'))) return true;
  if(vis(document.querySelector('input[autocomplete="no-thanks"]'))) return true;
  return textInputs().filter(function(i){return i.name!=='Email';}).length>0;
}
function netErr(){var s=String(document.body?document.body.innerText:'').toLowerCase()+' '+String(document.title||'').toLowerCase();return s.includes('err_connection')||s.includes('err_proxy')||s.includes('err_timed_out')||s.indexOf("site can")>-1&&s.indexOf('reached')>-1;}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<30000){await sleep(200);}
var deadline=Date.now()+30000;
while(Date.now()<deadline){
  if(netErr()) throw new Error('OASIS submission unreachable - rotate proxy.');
  if(!detailsUp()){ await sleep(1200); if(!detailsUp()) return 'done'; }
  await sleep(400);
}
throw new Error('OASIS signup did not complete after submit (details form still present).');
